import urllib.parse as urlparse

from requests.exceptions import InvalidSchema

from rainbow_admin.errors import CL5Exception
from rainbow_admin.file import RainbowFile
from rainbow_admin.utils import logger

try:
    import polaris
except ImportError:
    polaris = None
try:
    import l5sys
except ImportError:
    l5sys = None

if polaris:
    from polaris.api.consumer import create_consumer_by_config
    from polaris.pkg.config.api import Configuration

    config = Configuration()
    config.set_default()
    consumer = create_consumer_by_config(config)


class IntranetRainbowFile(RainbowFile):
    def requests_kwargs(self):
        result = super().requests_kwargs()
        parsed_url = urlparse.urlparse(self.real_url)
        host = parsed_url.hostname
        if host != self.group.cos_host:
            logger.warning(
                f"host of file url not match {repr(self.group.cos_host)}, please check."
            )
        if self.group.cl5_resolve_lib == "polaris":
            ip_port = polaris_get(self.group.cos_cl5)
        elif self.group.cl5_resolve_lib == "l5sys":
            ip_port = cl5_get(self.group.cos_cl5)
        else:
            if polaris:
                ip_port = polaris_get(self.group.cos_cl5)
            elif l5sys:
                ip_port = cl5_get(self.group.cos_cl5)
            else:
                raise InvalidSchema("please install l5sys or polaris.")
        if not self.secret_key:
            result["url"] = parsed_url._replace(scheme="http", netloc=ip_port).geturl()

        # 下载server side encrypted 文件时，要用https，且默认443端口
        else:
            # 北极星返回的 port 是80，但要用443，所以只替换域名为ip，保留https
            ip = ip_port.split(":")[0]
            result["url"] = parsed_url._replace(netloc=f"{ip}").geturl()
        result["headers"]["Host"] = parsed_url.hostname
        return result


def cl5_get(target: str) -> str:
    if not l5sys:
        raise CL5Exception("l5sys not install, please install l5sys first")
    try:
        mod_id, cmd_id = target.split(":")
        mod_id, cmd_id = int(mod_id), int(cmd_id)
    except:
        raise InvalidSchema(f"Not correct mod_id and cmd_id: {repr(target)}")
    payload = {"modId": mod_id, "cmdId": cmd_id}
    ret, qos = l5sys.ApiGetRoute(payload, 5)
    if ret < 0:
        raise CL5Exception(f"ApiGetRoute failed: {ret}")
    return f'{qos["hostIp"]}:{qos["hostPort"]}'


def polaris_get(target: str) -> str:
    import asyncio

    if not polaris:
        raise CL5Exception("polaris not install, please install polaris first")
    from polaris.pkg.model.service import GetOneInstanceRequest

    request = GetOneInstanceRequest(namespace="Production", service=target)
    loop = asyncio.get_event_loop()
    ret = loop.run_until_complete(consumer.async_get_one_instance(request))
    return f"{ret.get_host()}:{ret.get_port()}"
